const stdout = items[0].json.stdout;
if (!stdout) throw new Error('No stdout from SSH node.');

let parsed;
try { parsed = JSON.parse(stdout); } catch(e) { throw new Error('Failed to parse Python output: ' + stdout); }
if (parsed.error) throw new Error('Python script error: ' + parsed.error);

const d = parsed.data;
if (!d || d.weight == null) throw new Error('No weight data in response: ' + stdout);

// Check if reading is from today (Toronto time)
const measureDate = new Date(d.measure_ts);
const todayStr = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Toronto' });
const recordDateStr = measureDate.toLocaleDateString('en-CA', { timeZone: 'America/Toronto' });

if (recordDateStr !== todayStr) {
  // Return shouldLog: false — the If node will stop the chain here
  return [{ json: { shouldLog: false, reason: 'Reading from ' + recordDateStr + ', not today (' + todayStr + ').' } }];
}

// Dedup: skip if this exact measurement was already logged
const staticData = $getWorkflowStaticData('global');
if (staticData.lastLoggedTs === d.measure_ts) {
  return [{ json: { shouldLog: false, reason: 'Already logged ts: ' + d.measure_ts } }];
}

// wyze_sdk already returns weight in lbs — do NOT multiply by 2.20462
const weightLbs = Math.round(parseFloat(d.weight));
const bodyFat = (d.body_fat != null && d.body_fat !== 0) ? parseFloat(d.body_fat).toFixed(1) : '';

return [{ json: {
  shouldLog: true,
  measure_ts: d.measure_ts,
  todayStr,
  weightLbs,
  bodyFat,
  bmi: d.bmi,
  bmr: d.bmr,
  muscle: d.muscle,
  body_water: d.body_water,
  bone_mineral: d.bone_mineral,
  protein: d.protein,
  metabolic_age: d.metabolic_age,
  newRow: '| ' + todayStr + ' | ' + weightLbs + ' | ' + bodyFat + ' | |'
} }];

const staticData = $getWorkflowStaticData('global');
staticData.lastProcessedId = items[0].json.id;
return { success: true };

// items[0].json is the raw GitHub API response from Get File.
// It contains both .sha and .content (base64-encoded file text).
const item = items[0].json;

const sha = item.sha;
if (!sha) throw new Error('No sha in Get File response. Keys: ' + Object.keys(item).join(', '));

const rawContent = item.content;
if (!rawContent) throw new Error('No content in Get File response. Keys: ' + Object.keys(item).join(', '));

// GitHub returns content as base64 with \n every 60 chars — strip and decode
const currentContent = Buffer.from(rawContent.replace(/\n/g, ''), 'base64').toString('utf-8');

const health = $('Parse Python Output').first().json;

// Append new row, keeping exactly one trailing newline
const newContent = currentContent.trimEnd() + '\n' + health.newRow + '\n';

return [{ json: {
  sha,
  fileContent: Buffer.from(newContent, 'utf-8').toString('base64'),
  commitMessage: 'chore: auto-log weight ' + health.todayStr + ' — ' + health.weightLbs + ' lbs',
  todayStr: health.todayStr,
  weightLbs: health.weightLbs
} }];

const staticData = $getWorkflowStaticData('global');
staticData.lastLoggedTs = $('Parse Python Output').first().json.measure_ts;
return [{ json: { success: true, logged: true } }];
